INSERT INTO `myaac_news` VALUES (1,'Launch 11/out 20hrs','<p>Nostalgic server &eacute; um servidor criado por entusiastas do tibia oldschool, a mais pura&nbsp;<strong>nostalgia,&nbsp;</strong>vamos voltar aos bons tempos de tibia! Dias que ao upar um n&iacute;vel era incr&iacute;vel, por&eacute;m morrer era a maior decep&ccedil;&atilde;o. &Eacute;poca em que voc&ecirc; se divertia indo de uma cidade para outra andando, podia lurar monstros terr&iacute;veis para at&eacute; o inimagin&aacute;vel e matar um drag&atilde;o era algo que te trazia uma alegria incr&iacute;vel!</p>\r\n<p>RPG no sentido pr&oacute;prio destas palavras. Onde&nbsp;<strong>RPG&nbsp;</strong>significa jogar pap&eacute;is e intera&ccedil;&atilde;o constante entre os jogadores:&nbsp;<strong>criar guildas, estabelecer amizades, participar de guerras, formar alian&ccedil;as, quests entre outros.</strong>&nbsp;Mas acima de tudo&nbsp;<strong>aventuras e lutas constantes&nbsp;</strong>para nos encontrarmos em um mundo brutal, onde cada a&ccedil;&atilde;o pode ter graves consequ&ecirc;ncias.</p>\r\n<p><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"../images/Thais_Pencils.jpg\" alt=\"thais\" width=\"728\" height=\"266\" /></p>\r\n<p>&nbsp;</p>',1,1662905436,5,4,4,1665182469,'https://my-aac.org','','images/news/announcement.jpg',0),(2,'Launch','<p>Data estimada de lan&ccedil;amento do servidor: <span style=\"color: #339966;\"><strong>11/10/2022 &agrave;s 20:00 BRT</strong></span></p>',2,1662905436,4,4,4,1665185951,'','','images/news/announcement.jpg',0),(3,'Launch','<p><img style=\"float: left;\" src=\"../images/trumpeteer_withouttext.png\" alt=\"Announcement\" width=\"170\" height=\"285\" /><strong>An&uacute;ncio de lan&ccedil;amento do servidor</strong></p>\r\n<p>Server ser&aacute; lan&ccedil;ado no dia <span style=\"color: #339966;\"><strong>11/outubro/2022 &agrave;s 20:00 hrs BRT.</strong></span></p>\r\n<p>&nbsp;</p>\r\n<p><strong>Informa&ccedil;&otilde;es do server:</strong></p>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<ul style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 12px;\">\r\n<ul style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 12px;\">\r\n<li>IP:&nbsp;<strong>nostalgicot.online</strong>&nbsp;(Port:&nbsp;<strong>7171</strong>)</li>\r\n<li>Client:&nbsp;<strong>7.72</strong></li>\r\n<li>Online:&nbsp;<strong>24/7</strong></li>\r\n<li>World type:&nbsp;<strong>PVP&nbsp;<em>(Protection level: 1)</em></strong></li>\r\n<li>House rent: monthly.</li>\r\n</ul>\r\n</ul>\r\n<h2>&nbsp;</h2>\r\n<h2>Rates<img style=\"float: right;\" src=\"../images/newsreader_300x300.png\" alt=\"\" width=\"300\" height=\"300\" /></h2>\r\n<ul style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 12px;\">\r\n<ul style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 12px;\">\r\n<li>Exp Rate:&nbsp;<strong>x2</strong></li>\r\n<li>Magic Level:&nbsp;<strong>x2</strong></li>\r\n<li>Skills:&nbsp;<strong>x2</strong></li>\r\n<li>Loot:&nbsp;<strong>x2</strong></li>\r\n<li>Spawn:&nbsp;<strong>x1</strong></li>\r\n<li>Guilds:&nbsp;<strong>1 level</strong>&nbsp;(Create via website)</li>\r\n</ul>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<h2>Frags &amp; Skull system</h2>\r\n<ul style=\"color: #5a2800; font-family: Verdana, Arial, \'Times New Roman\', sans-serif; font-size: 12px;\">\r\n<li>PZ Lock:&nbsp;<strong>15 min</strong></li>\r\n<li>White Skull Time:&nbsp;<strong>15 min</strong></li>\r\n<li>Red skull length:&nbsp;<strong>3</strong><strong>0 days</strong></li>\r\n</ul>\r\n<p>&nbsp;</p>\r\n<p>&nbsp;</p>\r\n<p style=\"text-align: center;\"><img src=\"../images/Nostalgic Retro2.png\" alt=\"\" width=\"652\" height=\"866\" /></p>\r\n<p style=\"text-align: left;\"><strong>Evento de lan&ccedil;amento</strong></p>\r\n<p style=\"text-align: left;\">O servidor ser&aacute; lan&ccedil;ado com um evento j&aacute; em andamento, que funcionar&aacute; da seguinte maneira:<br />- Os 5 primeiros players que alcan&ccedil;arem o level 150 ir&atilde;o receber premios em <strong>PIX.</strong></p>\r\n<ol>\r\n<li style=\"text-align: left;\"><strong><span style=\"color: #339966;\">R$ 500,00</span></strong></li>\r\n<li style=\"text-align: left;\"><strong><span style=\"color: #339966;\">R$ 200,00</span></strong></li>\r\n<li style=\"text-align: left;\"><strong><span style=\"color: #339966;\">R$ 150,00</span></strong></li>\r\n<li style=\"text-align: left;\"><strong><span style=\"color: #339966;\">R$ 100,00</span></strong></li>\r\n<li style=\"text-align: left;\"><strong><span style=\"color: #339966;\">R$ 50,00</span></strong></li>\r\n</ol>\r\n<p><span style=\"color: #000000;\">Assim que o player atingir o level, o administrador ir&aacute; entrar em contato com o mesmo ingame para solicitar as informa&ccedil;&otilde;es para transa&ccedil;&atilde;o.</span></p>\r\n<p style=\"text-align: left;\">&nbsp;</p>\r\n<p style=\"text-align: left;\"><strong>Evento ativo do servidor</strong></p>\r\n<p style=\"text-align: left;\">Teremos um evento que ficar&aacute; sempre ativo, que funciona da seguinte maneira:</p>\r\n<p style=\"text-align: left;\">Nosso ADM far&aacute; lives com o GM/ADM sempre que poss&iacute;vel, voc&ecirc; ficando com essa live aberta, voc&ecirc; recebe pontos, esses pontos voc&ecirc; consegue trocar por <strong>premium time, gold converter e outfits</strong> que ser&atilde;o implementados futuramente.</p>\r\n<p style=\"text-align: left;\">acesse o&nbsp;<a title=\"Nostalgic Live\" href=\"http://twitch.tv/livedogoes\" target=\"_blank\" rel=\"noopener\"><strong>Link</strong> </a>para assistir a LIVE.</p>\r\n<p style=\"text-align: left;\">&nbsp;</p>\r\n<p style=\"text-align: left;\"><strong>DISCORD:</strong></p>\r\n<p style=\"text-align: left;\"><a title=\"discord\" href=\"https://discord.gg/MABvzZ9J7B\"><img style=\"display: block; margin-left: auto; margin-right: auto;\" src=\"../images/discord.png\" alt=\"discord\" width=\"162\" height=\"125\" /></a></p>\r\n<p style=\"text-align: left;\">Para interagir com o ADM, os streamers e outros players, acesse o discord do nosso server</p>',1,1665184754,1,4,4,1665959848,'0','','images/news/announcement.jpg',0),(4,'acc','<p>[Cria&ccedil;&atilde;o de contas] Website liberado para cria&ccedil;&atilde;o de contas.</p>',2,1665246390,4,4,0,0,'0','','',0);
/*!40000 ALTER TABLE `myaac_news` ENABLE KEYS */;
UNLOCK TABLES;

